// Pushes: economics, english, computer, reasoning, banking, tamil, current_affairs
require('dotenv').config({ path: require('path').resolve(__dirname, '../.env') });
const BASE  = process.env.EXPO_PUBLIC_UPSTASH_REDIS_REST_URL;
const TOKEN = process.env.EXPO_PUBLIC_UPSTASH_REDIS_REST_TOKEN;
const HDR   = { Authorization:`Bearer ${TOKEN}`, 'Content-Type':'application/json' };

async function pushSubject(key, questions) {
  await fetch(`${BASE}/del/${encodeURIComponent(key)}`, { method: 'POST', headers: HDR });
  const BATCH = 50;
  let total = 0;
  for (let i = 0; i < questions.length; i += BATCH) {
    const batch = questions.slice(i, i + BATCH);
    const values = batch.map(q => JSON.stringify(q));
    await fetch(`${BASE}/pipeline`, {
      method: 'POST', headers: HDR,
      body: JSON.stringify([['RPUSH', key, ...values]]),
    });
    total += batch.length;
  }
  console.log(`✓ ${key}: ${total} questions`);
}

